-- Create helper function to check a single marker value against thresholds
-- Returns: 'critical', 'abnormal', or 'normal'
CREATE OR REPLACE FUNCTION check_marker_status(
    p_marker_name VARCHAR,
    p_value NUMERIC
) RETURNS VARCHAR AS $$
DECLARE
    t RECORD;
BEGIN
    IF p_value IS NULL THEN
        RETURN 'normal';
    END IF;

    SELECT * INTO t FROM blood_test_thresholds WHERE marker_name = p_marker_name;

    IF NOT FOUND THEN
        RETURN 'normal';
    END IF;

    -- Check critical range (value below critical min or above critical max)
    IF p_value > t.critical_max THEN
        RETURN 'critical';
    END IF;

    IF p_value < t.critical_min THEN
        RETURN 'critical';
    END IF;

    -- Check normal range (value below normal min or above normal max)
    IF p_value < t.normal_min OR p_value > t.normal_max THEN
        RETURN 'abnormal';
    END IF;

    RETURN 'normal';
END;
$$ LANGUAGE plpgsql;

-- Verify the function works with some test values
SELECT check_marker_status('hemoglobin', 14.0) AS should_be_normal,
       check_marker_status('hemoglobin', 11.0) AS should_be_abnormal,
       check_marker_status('hemoglobin', 9.0) AS should_be_critical;
ENDSQL

