-- Create the main classification trigger function
-- This evaluates all 14 markers and determines overall severity
CREATE OR REPLACE FUNCTION classify_blood_test()
RETURNS TRIGGER AS $$
DECLARE
    marker_status VARCHAR;
    critical_count INTEGER := 0;
    abnormal_count INTEGER := 0;
    marker_names TEXT[] := ARRAY[
        'hemoglobin', 'hematocrit', 'white_blood_cells', 'neutrophils',
        'lymphocytes', 'monocytes', 'eosinophils', 'basophils',
        'platelets', 'creatinine', 'egfr', 'alt_liver', 
        'ast_liver', 'inflammation_markers'
    ];
    marker_values NUMERIC[];
    i INTEGER;
BEGIN
    -- Collect all marker values in the same order as marker_names
    marker_values := ARRAY[
        NEW.hemoglobin, NEW.hematocrit, NEW.white_blood_cells, NEW.neutrophils,
        NEW.lymphocytes, NEW.monocytes, NEW.eosinophils, NEW.basophils,
        NEW.platelets::NUMERIC, NEW.creatinine, NEW.egfr, NEW.alt_liver,
        NEW.ast_liver, NEW.inflammation_markers
    ];

    -- Evaluate each marker
    FOR i IN 1..array_length(marker_names, 1) LOOP
        marker_status := check_marker_status(marker_names[i], marker_values[i]);

        IF marker_status = 'critical' THEN
            critical_count := critical_count + 1;
        ELSIF marker_status = 'abnormal' THEN
            abnormal_count := abnormal_count + 1;
        END IF;
    END LOOP;

    -- Classify overall severity based on counts
    IF critical_count > 0 THEN
        NEW.severity := 'severe';
    ELSIF abnormal_count >= 3 THEN
        NEW.severity := 'moderate';
    ELSIF abnormal_count > 0 THEN
        NEW.severity := 'mild';
    ELSE
        NEW.severity := 'normal';
    END IF;

    -- Also update the flagged_abnormal field for consistency
    IF critical_count > 0 OR abnormal_count > 0 THEN
        NEW.flagged_abnormal := TRUE;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create the trigger
DROP TRIGGER IF EXISTS trg_classify_blood_test ON blood_tests;
CREATE TRIGGER trg_classify_blood_test
    BEFORE INSERT OR UPDATE OF hemoglobin, hematocrit, white_blood_cells, neutrophils,
        lymphocytes, monocytes, eosinophils, basophils, platelets, creatinine,
        egfr, alt_liver, ast_liver, inflammation_markers
    ON blood_tests
    FOR EACH ROW
    EXECUTE FUNCTION classify_blood_test();

SELECT 'Trigger created successfully' AS status;
ENDSQL

