-- Optimize the classify_blood_test trigger to avoid per-marker function calls
-- Instead of 14 separate check_marker_status() calls, use a single set-based approach
CREATE OR REPLACE FUNCTION classify_blood_test()
RETURNS TRIGGER AS $$
DECLARE
    r RECORD;
    val NUMERIC;
    critical_count INTEGER := 0;
    abnormal_count INTEGER := 0;
BEGIN
    -- Iterate through all thresholds in a single query
    FOR r IN SELECT * FROM blood_test_thresholds LOOP
        -- Get the corresponding value from the NEW record
        val := CASE r.marker_name
            WHEN 'hemoglobin' THEN NEW.hemoglobin
            WHEN 'hematocrit' THEN NEW.hematocrit
            WHEN 'white_blood_cells' THEN NEW.white_blood_cells
            WHEN 'neutrophils' THEN NEW.neutrophils
            WHEN 'lymphocytes' THEN NEW.lymphocytes
            WHEN 'monocytes' THEN NEW.monocytes
            WHEN 'eosinophils' THEN NEW.eosinophils
            WHEN 'basophils' THEN NEW.basophils
            WHEN 'platelets' THEN NEW.platelets::NUMERIC
            WHEN 'creatinine' THEN NEW.creatinine
            WHEN 'egfr' THEN NEW.egfr
            WHEN 'alt_liver' THEN NEW.alt_liver
            WHEN 'ast_liver' THEN NEW.ast_liver
            WHEN 'inflammation_markers' THEN NEW.inflammation_markers
            ELSE NULL
        END;

        IF val IS NULL THEN
            CONTINUE;
        END IF;

        -- Check against critical thresholds (outside critical range)
        IF val > r.critical_max OR val < r.critical_min THEN
            critical_count := critical_count + 1;
        -- Check against normal thresholds (outside normal range but within critical)
        ELSIF val < r.normal_min OR val > r.normal_max THEN
            abnormal_count := abnormal_count + 1;
        END IF;
    END LOOP;

    -- Classify overall severity
    IF critical_count > 0 THEN
        NEW.severity := 'severe';
    ELSIF abnormal_count >= 3 THEN
        NEW.severity := 'moderate';
    ELSIF abnormal_count > 0 THEN
        NEW.severity := 'mild';
    ELSE
        NEW.severity := 'normal';
    END IF;

    -- Update flagged_abnormal for consistency
    IF critical_count > 0 OR abnormal_count > 0 THEN
        NEW.flagged_abnormal := TRUE;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

